  1	import * as React from 'react';
  2	import { useSafeK8sWatchResource } from '@odf/core/hooks';
  3	import { backingStoreResource } from '@odf/core/resources';
  4	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import {
  7	  Dropdown,
  8	  DropdownItem,
  9	  DropdownList,
 10	  Divider,
 11	  MenuToggle,
 12	  MenuToggleElement,
 13	  Alert,
 14	} from '@patternfly/react-core';
 15	import { BackingStoreKind } from '../../types';
 16	import '../../style.scss';
 17	
 18	export const BackingStoreDropdown: React.FC<BackingStoreDropdownProps> = ({
 19	  onChange,
 20	  className,
 21	  selectedKey,
 22	  creatorDisabled,
 23	  launchBackingStoreModal,
 24	}) => {
 25	  const { t } = useCustomTranslation();
 26	  const [isOpen, setOpen] = React.useState(false);
 27	
 28	  const [nbsData, , nbsLoadErr] =
 29	    useSafeK8sWatchResource<BackingStoreKind[]>(backingStoreResource);
 30	  const noobaaBackingStores: BackingStoreKind[] = useDeepCompareMemoize(
 31	    nbsData,
 32	    true
 33	  );
 34	
 35	  const [nsName, setNSName] = React.useState('');
 36	  const handleDropdownChange = React.useCallback(
 37	    (e: React.KeyboardEvent<HTMLInputElement>) => {
 38	      setNSName(e.currentTarget.id);
 39	      onChange(
 40	        noobaaBackingStores.find(
 41	          (nbs) => nbs?.metadata?.name === e.currentTarget.id
 42	        )
 43	      );
 44	    },
 45	    [noobaaBackingStores, onChange]
 46	  );
 47	
 48	  const getDropdownItems = React.useCallback(
 49	    (backingStoreList: BackingStoreKind[]) => {
 50	      return backingStoreList.reduce(
 51	        (res, nbs) => {
 52	          res.push(
 53	            <DropdownItem
 54	              key={nbs.metadata.uid}
 55	              component="button"
 56	              id={nbs?.metadata?.name}
 57	              onClick={handleDropdownChange}
 58	              data-test={`${nbs?.metadata?.name}-dropdown-item`}
 59	              description={t('Provider {{provider}}', {
 60	                provider: nbs?.spec?.type,
 61	              })}
 62	            >
 63	              {nbs?.metadata?.name}
 64	            </DropdownItem>
 65	          );
 66	          return res;
 67	        },
 68	        !creatorDisabled
 69	          ? [
 70	              <DropdownItem
 71	                data-test="create-new-backingstore-button"
 72	                key="first-item"
 73	                component="button"
 74	                onClick={() => launchBackingStoreModal()}
 75	              >
 76	                {t('Create new BackingStore ')}
 77	              </DropdownItem>,
 78	              <Divider key="separator" />,
 79	            ]
 80	          : []
 81	      );
 82	    },
 83	    [creatorDisabled, t, handleDropdownChange, launchBackingStoreModal]
 84	  );
 85	
 86	  const dropdownItems = getDropdownItems(noobaaBackingStores);
 87	
 88	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 89	    <MenuToggle
 90	      ref={toggleRef}
 91	      id="nbs-dropdown-id"
 92	      data-test="nbs-dropdown-toggle"
 93	      onClick={() => setOpen(!isOpen)}
 94	      isExpanded={isOpen}
 95	      isDisabled={!!nbsLoadErr}
 96	      isFullWidth
 97	    >
 98	      {selectedKey || nsName || t('Select a backing store')}
 99	    </MenuToggle>
100	  );
101	
102	  return (
103	    <div className={className}>
104	      {nbsLoadErr && (
105	        <Alert
106	          className="nb-create-bc-step-page__danger"
107	          variant="danger"
108	          isInline
109	          title={t('An error has occured while fetching backing stores')}
110	        />
111	      )}
112	      <Dropdown
113	        className="dropdown--full-width"
114	        isOpen={isOpen}
115	        onSelect={() => setOpen(false)}
116	        onOpenChange={(open: boolean) => setOpen(open)}
117	        toggle={toggle}
118	        popperProps={{ width: 'trigger' }}
119	      >
120	        <DropdownList>{dropdownItems}</DropdownList>
121	      </Dropdown>
122	    </div>
123	  );
124	};
125	
126	type BackingStoreDropdownProps = {
127	  id: string;
128	  namespace: string;
129	  onChange?: (BackingStoreKind) => void;
130	  className?: string;
131	  selectedKey?: string;
132	  creatorDisabled?: boolean;
133	  launchBackingStoreModal?: () => void;
134	};

